const WISH_KEY="swati_wishlist";function getWishlist(){try{return JSON.parse(localStorage.getItem(WISH_KEY))||[]}catch(t){return[]}}function isWishlisted(t){return getWishlist().includes(t)}function toggleWishlist(t){let e=getWishlist();const s=getProductById(t);return e.includes(t)?(e=e.filter(e=>e!==t),showToast(`${s?s.name:"Item"} removed from wishlist`,"info")):(e.push(t),showToast(`${s?s.name:"Item"} added to wishlist`,"success"),pulseIcon("wishIconBadge")),localStorage.setItem(WISH_KEY,JSON.stringify(e)),updateWishCount(),e.includes(t)}function updateWishCount(){const t=getWishlist().length;document.querySelectorAll("[data-wish-count]").forEach(e=>{e.textContent=t,e.style.display=t>0?"flex":"none"})}document.addEventListener("DOMContentLoaded",updateWishCount);